  1→/**
  2→ * Content Mediation — Two-layer authentication middleware
  3→ *
  4→ * Layer 1: API key validation (X-API-Key header) — identifies the integration/tenant
  5→ * Layer 2: User JWT validation (Authorization: Bearer) — identifies the end user
  6→ */
  7→
  8→import { Request, Response, NextFunction } from 'express';
  9→import { eq } from 'drizzle-orm';
 10→import { drizzle } from 'drizzle-orm/node-postgres';
 11→import crypto from 'node:crypto';
 12→import * as jose from 'jose';
 13→import { contentApiKeys } from '../schema.js';
 14→
 15→type DrizzleClient = ReturnType<typeof drizzle>;
 16→
 17→// Extend Express Request with auth context
 18→declare global {
 19→  namespace Express {
 20→    interface Request {
 21→      apiKeyRecord?: typeof contentApiKeys.$inferSelect;
 22→      userId?: string;
 23→      tenantId?: string;
 24→    }
 25→  }
 26→}
 27→
 28→export function hashApiKey(key: string): string {
 29→  return crypto.createHash('sha256').update(key).digest('hex');
 30→}
 31→
 32→export function createAuthMiddleware(db: DrizzleClient) {
 33→  return {
 34→    /**
 35→     * Layer 1: Validate X-API-Key header against stored key hashes.
 36→     * Attaches apiKeyRecord and tenantId to req on success.
 37→     */
 38→    validateApiKey: async (req: Request, res: Response, next: NextFunction): Promise<void> => {
 39→      const apiKey = req.headers['x-api-key'] as string | undefined;
 40→      if (!apiKey) {
 41→        res.status(401).json({ error: 'missing_api_key', message: 'X-API-Key header required' });
 42→        return;
 43→      }
 44→
 45→      const keyHash = hashApiKey(apiKey);
 46→      const rows = await db
 47→        .select()
 48→        .from(contentApiKeys)
 49→        .where(eq(contentApiKeys.keyHash, keyHash))
 50→        .limit(1);
 51→      const keyRecord = rows[0];
 52→
 53→      if (!keyRecord || !keyRecord.isActive) {
 54→        res.status(401).json({ error: 'invalid_api_key', message: 'Invalid or inactive API key' });
 55→        return;
 56→      }
 57→
 58→      req.apiKeyRecord = keyRecord;
 59→      req.tenantId = keyRecord.tenantId;
 60→
 61→      // Update lastUsedAt — fire and forget, non-blocking
 62→      db.update(contentApiKeys)
 63→        .set({ lastUsedAt: new Date() })
 64→        .where(eq(contentApiKeys.id, keyRecord.id))
 65→        .catch(() => {});
 66→
 67→      next();
 68→    },
 69→
 70→    /**
 71→     * Layer 2: Validate Authorization: Bearer JWT against the JWKS URI
 72→     * stored on the API key record. Must run after validateApiKey.
 73→     */
 74→    validateUserToken: async (req: Request, res: Response, next: NextFunction): Promise<void> => {
 75→      const authHeader = req.headers.authorization;
 76→      if (!authHeader?.startsWith('Bearer ')) {
 77→        res.status(401).json({
 78→          error: 'missing_user_token',
 79→          message: 'Authorization: Bearer <token> required',
 80→        });
 81→        return;
 82→      }
 83→
 84→      const token = authHeader.substring(7);
 85→      const apiKeyRecord = req.apiKeyRecord;
 86→      if (!apiKeyRecord) {
 87→        res.status(401).json({
 88→          error: 'missing_api_key',
 89→          message: 'API key validation must precede user token validation',
 90→        });
 91→        return;
 92→      }
 93→
 94→      const { jwksUri, issuer, audience } = apiKeyRecord;
 95→      if (!jwksUri) {
 96→        res.status(401).json({
 97→          error: 'invalid_configuration',
 98→          message: 'JWKS URI not configured for this API key',
 99→        });
100→        return;
101→      }
102→
103→      try {
104→        const JWKS = jose.createRemoteJWKSet(new URL(jwksUri));
105→        const { payload } = await jose.jwtVerify(token, JWKS, {
106→          ...(issuer ? { issuer } : {}),
107→          ...(audience ? { audience } : {}),
108→        });
109→
110→        req.userId = payload.sub;
111→        next();
112→      } catch (err) {
113→        if (err instanceof jose.errors.JWTExpired) {
114→          res.status(401).json({ error: 'token_expired', message: 'User token has expired' });
115→          return;
116→        }
117→        res.status(401).json({ error: 'invalid_user_token', message: 'Invalid user token' });
118→      }
119→    },
120→  };
121→}
