    .limit(1);

  if (!task) return res.status(404).send('Task not found');

  await db
    .update(scheduledTasks)
    .set({ enabled: !task.enabled, updatedAt: new Date() })
    .where(eq(scheduledTasks.id, task.id));

  await reloadTask(task.id);

  res.redirect('/tasks');
