                <span class="${run.status === 'COMPLETED' ? 'run-success' : run.status === 'FAILED' ? 'run-failed' : ''}">
                  ${run.status} (${run.duration || 0}ms) - ${new Date(run.startedAt).toLocaleString()}
                </span>
              `).join(' | ')}
