 37→exportRouter.post('/tenants/:tenantId/exports/excel', requireTokenAuth, async (req: AuthenticatedRequest, res: Response) => {
 38→  const startedAt = Date.now();
 39→  const user = req.authUser;
 40→  const tenantId = req.params.tenantId;
 41→
 42→  if (!user) {
 43→    res.status(401).json({ error: 'Unauthorized' });
 44→    return;
 45→  }
 46→
 47→  const body = (req.body && typeof req.body === 'object' ? req.body : {}) as ExcelExportRequest;
 48→
 49→  try {
 50→    const { job, downloadUrl } = await createExcelExportJob({
 51→      userId: user.id,
 52→      tenantId,
 53→      request: body,
 54→      baseUrl: inferredBaseUrl(req),
 55→    });
 56→
 57→    await writeAudit(
 58→      user.id,
 59→      'ops_export_excel_api_create',
 60→      {
 61→        tenant_id: tenantId,
 62→        scope: body.scope || 'current_view',
 63→        locations: body.locations || 'current',
 64→        scenario_id: body.scenario_id || null,
 65→      },
 66→      true,
 67→      Date.now() - startedAt
 68→    );
 69→
 70→    res.status(201).json({
 71→      export_id: job.id,
 72→      tenant_id: job.tenantId,
 73→      status: job.status,
 74→      scope: job.scope,
 75→      locations: job.locations,
 76→      created_at: job.createdAt,
 77→      updated_at: job.updatedAt,
 78→      download_url: downloadUrl,
 79→      expires_at: job.downloadExpiresAt,
 80→      file_name: job.fileName,
 81→      file_size_bytes: job.fileSizeBytes,
 82→    });
 83→  } catch (error) {
 84→    const message = error instanceof Error ? error.message : 'Export generation failed';
 85→
 86→    await writeAudit(
 87→      user.id,
 88→      'ops_export_excel_api_create',
 89→      {
 90→        tenant_id: tenantId,
 91→        scope: body.scope || 'current_view',
 92→        locations: body.locations || 'current',
 93→        scenario_id: body.scenario_id || null,
 94→      },
 95→      false,
 96→      Date.now() - startedAt,
 97→      message
 98→    );
 99→
100→    if (message.includes('not authorized')) {
101→      res.status(403).json({ error: message });
102→      return;
103→    }
104→    res.status(500).json({ error: message });
105→  }
106→});
