147→exportRouter.get('/exports/download/:token', async (req: Request, res: Response) => {
148→  const token = req.params.token;
149→  const resolved = resolveDownloadToken(token);
150→
151→  if (!resolved) {
152→    res.status(404).json({ error: 'Download link is invalid or expired' });
153→    return;
154→  }
155→
156→  const { job, filePath } = resolved;
157→  const fileName = job.fileName || `${job.id}.xlsx`;
158→  res.setHeader('Content-Type', 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet');
159→  res.download(filePath, fileName);
160→});
