 1→/**
 2→ * Token Encryption Utilities
 3→ * AES-256 encryption for OAuth tokens at rest
 4→ */
 5→
 6→import CryptoJS from 'crypto-js';
 7→
 8→const ENCRYPTION_KEY = process.env.TOKEN_ENCRYPTION_KEY;
 9→
10→if (!ENCRYPTION_KEY) {
11→  console.warn('⚠️  TOKEN_ENCRYPTION_KEY not set - tokens will not be encrypted!');
12→}
13→
14→/**
15→ * Encrypt a token for storage
16→ */
17→export function encryptToken(token: string): string {
18→  if (!ENCRYPTION_KEY) {
19→    return token; // Dev fallback - not for production!
20→  }
21→  return CryptoJS.AES.encrypt(token, ENCRYPTION_KEY).toString();
22→}
23→
24→/**
25→ * Decrypt a stored token
26→ */
27→export function decryptToken(encryptedToken: string): string {
28→  if (!ENCRYPTION_KEY) {
29→    return encryptedToken;
30→  }
31→  const bytes = CryptoJS.AES.decrypt(encryptedToken, ENCRYPTION_KEY);
32→  return bytes.toString(CryptoJS.enc.Utf8);
33→}
34→
35→/**
36→ * Generate a random MCP token for user authentication
37→ */
38→export function generateMcpToken(): string {
39→  return CryptoJS.lib.WordArray.random(32).toString(CryptoJS.enc.Hex);
40→}
41→
42→/**
43→ * Generate OAuth state parameter
44→ */
45→export function generateOAuthState(): string {
46→  return CryptoJS.lib.WordArray.random(16).toString(CryptoJS.enc.Hex);
47→}
